object AppLogger {
    private const val TAG = "AppLog"

    data class Config(
        val enabled: Boolean = true,
        val logToLogcat: Boolean = true,
        val logToTimber: Boolean = true,
        val minPriority: Int = Log.VERBOSE,
        val includeThread: Boolean = true,
