        val redactJsonFieldNames: Set<String> = setOf("password", "token", "access_token", "refresh_token", "secret", "otp")
    )

    private val configRef = AtomicReference(Config())
    private val sessionIdRef = AtomicReference<String?>(null)
    private val userIdRef = AtomicReference<String?>(null)

    fun init(context: Context, config: Config = Config(), plantTimberDebugTreeIfNone: Boolean = true) {
        configRef.set(config)
        if (config.logToTimber && plantTimberDebugTreeIfNone) {
            try {
                Timber.plant(object : Timber.DebugTree() {
                    override fun createStackElementTag(element: StackTraceElement): String {
                        return "${super.createStackElementTag(element)}:${element.lineNumber}"
                    }
                })
            } catch (_: Throwable) {
            }
        }
        if (config.includeDeviceInfo) {
            v(TAG, "Device", mapOf(
                "manufacturer" to Build.MANUFACTURER,
                "brand" to Build.BRAND,
                "model" to Build.MODEL,
                "device" to Build.DEVICE,
                "product" to Build.PRODUCT,
                "sdk" to Build.VERSION.SDK_INT,
                "release" to Build.VERSION.RELEASE
            ))
        }
        if (sessionIdRef.get() == null) sessionIdRef.set(UUID.randomUUID().toString())
        v(TAG, "Logger initialized", mapOf("sessionId" to sessionIdRef.get()))
    }

    fun setSessionId(sessionId: String?) {
        sessionIdRef.set(sessionId)
        v(TAG, "Session updated", mapOf("sessionId" to sessionIdRef.get()))
    }

    fun setUserId(userId: String?) {
        userIdRef.set(userId)
        v(TAG, "User updated", mapOf("userId" to userIdRef.get()))
    }

    fun v(tag: String = TAG, message: String, meta: Map<String, Any?> = emptyMap()) = log(Log.VERBOSE, tag, message, null, meta)
    fun d(tag: String = TAG, message: String, meta: Map<String, Any?> = emptyMap()) = log(Log.DEBUG, tag, message, null, meta)
    fun i(tag: String = TAG, message: String, meta: Map<String, Any?> = emptyMap()) = log(Log.INFO, tag, message, null, meta)
    fun w(tag: String = TAG, message: String, tr: Throwable? = null, meta: Map<String, Any?> = emptyMap()) = log(Log.WARN, tag, message, tr, meta)
    fun e(tag: String = TAG, message: String, tr: Throwable? = null, meta: Map<String, Any?> = emptyMap()) = log(Log.ERROR, tag, message, tr, meta)
    fun wtf(tag: String = TAG, message: String, tr: Throwable? = null, meta: Map<String, Any?> = emptyMap()) = log(Log.ASSERT, tag, message, tr, meta)

    fun exception(tr: Throwable, tag: String = TAG, message: String = "Exception", meta: Map<String, Any?> = emptyMap()) {
        log(Log.ERROR, tag, message, tr, meta + mapOf("stacktrace" to stackTraceToString(tr)))
    }

    fun authAttempt(
        usernameOrEmail: String?,
        method: String,
        success: Boolean,
        failureReason: String? = null,
        meta: Map<String, Any?> = emptyMap()
    ) {
        val safeUser = usernameOrEmail?.let { redactLikelyCredential(it) }
        val m = linkedMapOf<String, Any?>(
            "event" to "auth_attempt",
            "method" to method,
            "user" to safeUser,
            "success" to success,
            "failureReason" to failureReason,
            "sessionId" to sessionIdRef.get(),
