    }

    fun dbQuery(
        sql: String,
        args: List<Any?>? = null,
        rows: Int? = null,
        durationMs: Long? = null,
        meta: Map<String, Any?> = emptyMap()
    ) {
        val redactedArgs = args?.map { redactDbArg(it) }
        val m = linkedMapOf<String, Any?>(
            "event" to "db_query",
            "sql" to sql,
            "args" to redactedArgs,
            "rows" to rows,
            "durationMs" to durationMs,
            "sessionId" to sessionIdRef.get(),
            "userId" to userIdRef.get()
        )
        d("DB", "Database query", m + meta)
    }

    private fun log(priority: Int, tag: String, message: String, tr: Throwable?, meta: Map<String, Any?>) {
        val cfg = configRef.get()
        if (!cfg.enabled) return
        if (priority < cfg.minPriority) return

        val sb = StringBuilder()
        if (cfg.includeThread) {
            sb.append("[t=").append(Thread.currentThread().name).append("] ")
        }
        val sid = sessionIdRef.get()
        if (sid != null) sb.append("[sid=").append(sid).append("] ")
        val uid = userIdRef.get()
        if (uid != null) sb.append("[uid=").append(uid).append("] ")
        sb.append(message)

        if (meta.isNotEmpty()) {
            sb.append(" | ")
            sb.append(metaToString(meta, cfg))
        }

        val finalMsg = sb.toString()
        if (cfg.logToTimber) {
            when (priority) {
                Log.VERBOSE -> Timber.tag(tag).v(tr, finalMsg)
                Log.DEBUG -> Timber.tag(tag).d(tr, finalMsg)
                Log.INFO -> Timber.tag(tag).i(tr, finalMsg)
                Log.WARN -> Timber.tag(tag).w(tr, finalMsg)
                Log.ERROR -> Timber.tag(tag).e(tr, finalMsg)
                Log.ASSERT -> Timber.tag(tag).wtf(tr, finalMsg)
                else -> Timber.tag(tag).d(tr, finalMsg)
            }
        }
        if (cfg.logToLogcat) {
            if (tr != null) {
                Log.println(priority, tag, "$finalMsg\n${stackTraceToString(tr)}")
            } else {
                Log.println(priority, tag, finalMsg)
            }
        }
    }

    private fun metaToString(meta: Map<String, Any?>, cfg: Config): String {
        val parts = ArrayList<String>(meta.size)
        for ((k, v) in meta) {
            val vv = when {
                v is String -> redactStringIfSensitive(k, v, cfg)
                v is Headers -> headersToString(v, cfg)
                v is Throwable -> stackTraceToString(v)
                else -> v
            }
            parts.add("$k=$vv")
        }
        return parts.joinToString(", ")
    }

    private fun redactStringIfSensitive(key: String, value: String, cfg: Config): String {
        val kl = key.lowercase(Locale.US)
        if (cfg.redactQueryParamNames.contains(kl) || cfg.redactJsonFieldNames.contains(kl)) return "██REDACTED██"
        if (kl.contains("password") || kl.contains("token") || kl.contains("secret") || kl.contains("otp")) return "██REDACTED██"
        return value
    }

    private fun redactLikelyCredential(input: String): String {
        val trimmed = input.trim()
        if (trimmed.contains("@")) {
            val idx = trimmed.indexOf("@")
            val left = trimmed.take(idx)
            val right = trimmed.drop(idx)
            val maskedLeft = when {
                left.length <= 2 -> "██"
                else -> left.take(2) + "██"
            }
            return maskedLeft + right
        }
        return when {
            trimmed.length <= 3 -> "██"
            else -> trimmed.take(2) + "██" + trimmed.takeLast(1)
        }
    }

    private fun redactDbArg(arg: Any?): Any? {
        if (arg == null) return null
        val s = arg.toString()
        val sl = s.lowercase(Locale.US)
        if (sl.contains("bearer ") || sl.contains("eyj") || sl.contains("password") || sl.contains("token")) return "██REDACTED██"
        return arg
    }

    fun stackTraceToString(tr: Throwable): String {
        return try {
            val sw = StringWriter()
            val pw = PrintWriter(sw)
            tr.printStackTrace(pw)
            pw.flush()
            sw.toString()
        } catch (_: Throwable) {
            tr.toString()
        }
    }

    private fun headersToString(headers: Headers, cfg: Config): String {
        val sb = StringBuilder()
        for (i in 0 until headers.size) {
            val name = headers.name(i)
            val value = headers.value(i)
            val redacted = if (cfg.redactHeaderNames.any { it.equals(name, ignoreCase = true) }) "██REDACTED██" else value
            sb.append(name).append(": ").append(redacted)
            if (i < headers.size - 1) sb.append("; ")
        }
        return sb.toString()
    }

    fun redactHeaders(headers: Headers, cfg: Config = configRef.get()): Headers {
        val b = Headers.Builder()
        for (i in 0 until headers.size) {
            val name = headers.name(i)
            val value = headers.value(i)
            val redacted = if (cfg.redactHeaderNames.any { it.equals(name, ignoreCase = true) }) "██REDACTED██" else value
            b.add(name, redacted)
        }
        return b.build()
    }
}

class ApiLoggingInterceptor(
    private val configProvider: () -> AppLogger.Config = { AppLogger.Config() },
    private val tag: String = "API"
) : Interceptor {

    override fun intercept(chain: Interceptor.Chain): Response {
        val cfg = configProvider()
        val request = chain.request()

        val requestId = UUID.randomUUID().toString()
        val startNs = System.nanoTime()

        logRequest(cfg, requestId, request)

        return try {
            val response = chain.proceed(request)
            val tookMs = (System.nanoTime() - startNs) / 1_000_000

            logResponse(cfg, requestId, request, response, tookMs)
            response
        } catch (t: Throwable) {
            val tookMs = (System.nanoTime() - startNs) / 1_000_000
            AppLogger.exception(
                t,
                tag = tag,
                message = "API failed",
                meta = mapOf(
                    "event" to "api_error",
                    "requestId" to requestId,
                    "method" to request.method,
                    "url" to request.url.toString(),
                    "durationMs" to tookMs,
                    "headers" to AppLogger.redactHeaders(request.headers, cfg).toString(),
                    "body" to readRequestBodyAsString(request, cfg)
                )
            )
            throw t
        }
    }

    private fun logRequest(cfg: AppLogger.Config, requestId: String, request: Request) {
        val meta = linkedMapOf<String, Any?>(
            "event" to "api_request",
            "requestId" to requestId,
            "method" to request.method,
            "url" to request.url.toString(),
            "headers" to AppLogger.redactHeaders(request.headers, cfg).toString(),
            "body" to readRequestBodyAsString(request, cfg)
        )
        AppLogger.v(tag, "API request", meta)
    }

    private fun logResponse(cfg: AppLogger.Config, requestId: String, request: Request, response: Response, tookMs: Long) {
        val peekedBody = try {
            val body = response.body
            if (body == null) null else {
                val bytes = response.peekBody((cfg.maxBodyChars.toLong()).coerceAtMost(2_000_000L)).bytes()
                val charset = body.contentType()?.charset(Charsets.UTF_8) ?: Charsets.UTF_8
                val str = bytes.toString(charset).truncate(cfg.maxBodyChars)
                str
            }
        } catch (t: Throwable) {
            "!! failed to read response body: ${t::class.java.simpleName}: ${t.message}"
        }

        val meta = linkedMapOf<String, Any?>(
            "event" to "api_response",
            "requestId" to requestId,
            "method" to request.method,
            "url" to request.url.toString(),
            "code" to response.code,
            "message" to response.message,
            "durationMs" to tookMs,
            "headers" to AppLogger.redactHeaders(response.headers, cfg).toString(),
            "body" to peekedBody
        )
        AppLogger.v(tag, "API response", meta)
    }

    private fun readRequestBodyAsString(request: Request, cfg: AppLogger.Config): String? {
        return try {
            val body = request.body ?: return null
            val buffer = Buffer()
            val copy = body.safeCopy()
            copy.writeTo(buffer)
            val contentType = body.contentType()
            val charset = contentType?.charset(Charsets.UTF_8) ?: Charsets.UTF_8
            buffer.readByteString().toString(charset).truncate(cfg.maxBodyChars)
        } catch (t: Throwable) {
            "!! failed to read request body: ${t::class.java.simpleName}: ${t.message}"
        }
    }

    private fun RequestBody.safeCopy(): RequestBody {
        val original = this
        val contentType: MediaType? = original.contentType()
        val contentLength: Long = try { original.contentLength() } catch (_: Throwable) { -1L }
        val buffer = Buffer()
        return try {
            original.writeTo(buffer)
            val bytes = buffer.readByteArray()
            object : RequestBody() {
                override fun contentType(): MediaType? = contentType
                override fun contentLength(): Long = if (contentLength >= 0) contentLength else bytes.size.toLong()
                override fun writeTo(sink: okio.BufferedSink) {
                    sink.write(bytes)
                }
            }
        } catch (_: Throwable) {
            original
        }
    }

    private fun String.truncate(maxChars: Int): String {
        if (length <= maxChars) return this
        return substring(0, maxChars) + "…(truncated, len=$length)"
    }
}

class LoggingUncaughtExceptionHandler(
    private val delegate: Thread.UncaughtExceptionHandler? = Thread.getDefaultUncaughtExceptionHandler()
) : Thread.UncaughtExceptionHandler {
    override fun uncaughtException(t: Thread, e: Throwable) {
        AppLogger.exception(
            e,
            tag = "Crash",
            message = "Uncaught exception",
            meta = mapOf("thread" to t.name)
        )
        delegate?.uncaughtException(t, e)
    }
}

interface AuthLogger {
