        AppLogger.authAttempt(usernameOrEmail, method, success, failureReason, meta)
    }
}

interface DbLogger {
    fun logQuery(sql: String, args: List<Any?>? = null, rows: Int? = null, durationMs: Long? = null, meta: Map<String, Any?> = emptyMap())
}

class DefaultDbLogger : DbLogger {
    override fun logQuery(sql: String, args: List<Any?>?, rows: Int?, durationMs: Long?, meta: Map<String, Any?>) {
        AppLogger.dbQuery(sql, args, rows, durationMs, meta)
    }
}

object LoggingInstaller {
    fun installCrashLogging() {
        val current = Thread.getDefaultUncaughtExceptionHandler()
        if (current !is LoggingUncaughtExceptionHandler) {
            Thread.setDefaultUncaughtExceptionHandler(LoggingUncaughtExceptionHandler(current))
        }
    }
